import axios from "axios";

const API = "http://127.0.0.1:8000";

export const uploadPDF = (formData) => {
  return axios.post(`${API}/upload`, formData);
};

export const askAI = (question) => {
  return axios.get(`${API}/ask`, {
    params: { question }
  });
};
